func:
const payload = msg.payload || {};
const name = payload.name || "Unknown Client";
const phone = payload.phone || "No phone provided";
const county = payload.county || "Unknown County";
const charges = payload.charges || "Not specified";
const bondAmount = payload.bondAmount ? `$${payload.bondAmount}` : "TBD";

msg.headers = {
    "Authorization": "Bearer " + ((global.get("env").SLACK_BOT_TOKEN || global.get("SLACK_TOKEN") || "") || "") ,
    "Content-Type": "application/json; charset=utf-8"
};

msg.payload = {
    "channel": "C09MP494D1T",
    "blocks": [
        {
            "type": "header",
            "text": {
                "type": "plain_text",
                "text": "🚨 New Intake Lead - " + county,
                "emoji": true
            }
        },
        {
            "type": "divider"
        },
        {
            "type": "section",
            "fields": [
                {
                    "type": "mrkdwn",
                    "text": "*Client Name:*\n" + name
                },
                {
                    "type": "mrkdwn",
                    "text": "*Phone:*\n" + phone
                }
            ]
        },
        {
            "type": "section",
            "fields": [
                {
                    "type": "mrkdwn",
                    "text": "*Charges:*\n" + charges
                },
                {
                    "type": "mrkdwn",
                    "text": "*Bond Amount:*\n" + bondAmount
                }
            ]
        },
        {
            "type": "divider"
        },
        {
            "type": "context",
            "elements": [
                {
                    "type": "mrkdwn",
                    "text": "_Triggered by Wix Webhook Node-RED Flow_"
                }
            ]
        }
    ]
};

return msg;

// Format Scrape Alert — aligned with Master 34 schema
// Feeds Live Inmate Ticker (latest bookings panel)
try {
    const raw = msg.payload;
    let records = Array.isArray(raw) ? raw :
                  (raw && Array.isArray(raw.records)) ? raw.records :
                  (raw && Array.isArray(raw.arrests)) ? raw.arrests :
                  (raw && Array.isArray(raw.data)) ? raw.data : [];

    if (!records.length) {
        node.status({fill:'grey', shape:'ring', text:'No records'});
        return null;
    }

    // Normalize each record to Master 34 field names with fallbacks
    const normalized = records.map(r => ({
        Full_Name:    r.Full_Name || r.full_name || r.name || r.DefendantName || 'Unknown',
        Charges:      r.Charges || r.charges || r.charge || 'Pending',
        Bond_Amount:  parseFloat(String(r.Bond_Amount || r.BondAmount || r.bondAmount || r.bond || r.total_bond_amount || '0').replace(/[^0-9.]/g, '')) || 0,
        County:       r.County || r.county || 'Unknown',
        Booking_Date: r.Booking_Date || r.booking_date || r.bookingDate || new Date().toISOString().split('T')[0],
        Booking_Number: r.Booking_Number || r.booking_number || r.bookingNumber || '',
        Status:       r.Status || r.status || 'Unposted',
        _isNew:       true
    }));

    // Sort by bond amount descending
    normalized.sort((a, b) => b.Bond_Amount - a.Bond_Amount);

    // Store in global for periodic refresh
    global.set('latest_bookings', normalized);
    global.set('latest_bookings_ts', new Date().toISOString());

    // Update scraper health
    const county = normalized[0]?.County || 'Unknown';
    let health = global.get('scraper_health') || [];
    const idx = health.findIndex(h => h.county === county);
    const entry = {
        county: county,
        status: '🟢 Live',
        last_run: new Date().toLocaleTimeString('en-US', {hour:'2-digit', minute:'2-digit'}),
        records: normalized.length
    };
    if (idx >= 0) health[idx] = entry; else health.push(entry);
    global.set('scraper_health', health);

    msg.payload = normalized;
    node.status({fill:'green', shape:'dot', text: normalized.length + ' bookings'});
    return msg;
} catch (e) {
    node.error('Format Scrape Alert error: ' + e.message);
    node.status({fill:'red', shape:'dot', text:'Error: ' + e.message});
    return null;
}

msg.payload = {
    action: 'investigate',
    firstName: msg.payload.firstName,
    lastName: msg.payload.lastName,
    dob: msg.payload.dob
};
return msg;

msg.payload = {
    action: 'sendSlackAlert',
    text: `🖥️ **TERMINAL EXEC:** ${msg.payload}`,
    channel: '#alerts'
};
return msg;

msg.payload = {
    action: 'generate_magic_link',
    phone: msg.payload.clientPhone,
    caseNumber: msg.payload.caseNumber
};
return msg;

let score = 50;
let credit = parseInt(msg.payload.creditScore) || 500;
let years = parseInt(msg.payload.yearsEmployed) || 0;
let home = msg.payload.homeowner === true;

if (credit > 700) score -= 20;
else if (credit < 550) score += 20;

if (years > 5) score -= 15;
else if (years < 1) score += 10;

if (home) score -= 15;
else score += 10;

score = Math.max(0, Math.min(100, score));
msg.payload = {
    action: 'sendSlackAlert',
    text: `📊 **Risk Analysis Complete**\nFlight Risk Score: ${score}/100\nCredit: ${credit}\nEmployed: ${years} yrs\nHomeowner: ${home}`,
    channel: '#alerts'
};
return msg;

// Build dynamic scraper payload from dashboard context or defaults
const county = msg.payload?.county || global.get('active_county') || 'lee';
const dateRange = msg.payload?.dateRange || 'today';
const forceScrape = msg.payload?.force || false;

msg.payload = {
    action: 'scrapeCounty',
    county: county.toLowerCase(),
    dateRange: dateRange,
    force: forceScrape,
    requestedAt: new Date().toISOString(),
    source: 'node-red-dashboard'
};

node.status({ fill: 'blue', shape: 'dot', text: `Scraping ${county}...` });
return msg;

// Build court email processing request
const emailSource = msg.payload?.source || 'court-clerk';
const filterType = msg.payload?.filter || 'unprocessed';
const lookbackDays = msg.payload?.days || 7;

msg.payload = {
    action: 'processCourtEmails',
    source: emailSource,
    filter: filterType,
    lookbackDays: lookbackDays,
    maxResults: 50,
    requestedAt: new Date().toISOString(),
    requestedBy: 'node-red'
};

node.status({ fill: 'blue', shape: 'dot', text: `Processing ${emailSource} emails...` });
return msg;

/* Generate Liability Report via GAS */
if (global.get('SYSTEM_SHUTDOWN')) {
    node.status({fill:'red',shape:'ring',text:'SHUTDOWN'});
    return null;
}

const gasUrl = global.get('GAS_URL_OPS') || global.get('GAS_URL');
if (!gasUrl) {
    node.error('No GAS URL configured');
    return null;
}

const ts = new Date().toISOString();
msg.payload = {
    action: 'generateLiabilityReport',
    requestedAt: ts,
    source: 'node-red-dashboard',
    reportParams: {
        includeActive: true,
        includeForfeited: true,
        includeExonerated: false,
        asOfDate: new Date().toISOString().split('T')[0],
        groupBy: 'county',
        sortBy: 'bondAmount',
        sortOrder: 'desc'
    }
};

global.set('last_run_liabilityReport', ts);
node.status({fill:'blue',shape:'dot',text:'Generating...'});
return msg;

/* Generate Commissions (1099) Report via GAS */
if (global.get('SYSTEM_SHUTDOWN')) {
