/* Install automated payment reconciliation cron via GAS */
if (global.get('SYSTEM_SHUTDOWN')) {
    node.status({fill:'red',shape:'ring',text:'SHUTDOWN'});
    return null;
}

const gasUrl = global.get('GAS_URL_OPS') || global.get('GAS_URL');
if (!gasUrl) {
    node.error('No GAS URL configured');
    return null;
}

const ts = new Date().toISOString();
msg.payload = {
    action: 'installPaymentRecon',
    requestedAt: ts,
    source: 'node-red-dashboard',
    config: {
        frequency: 'daily',
        timeOfDay: '06:00',
        timezone: 'America/New_York',
        reconcileAgainst: ['swipesimple', 'google_sheets'],
        reminderDaysBefore: [3, 1, 0],
        overdueGraceDays: 3,
        overdueAction: 'send_warning_sms',
        collectionThresholdDays: 30,
        channels: ['sms', 'whatsapp'],
        reminderTemplate: '🍀 Shamrock Bail Bonds Reminder: Your payment of ' + '$' + '{{amount}} for the bond of {{defendant_name}} is due on {{due_date}}. Pay online or call (239) 332-2245.',
        overdueTemplate: '⚠️ NOTICE: Your payment of ' + '$' + '{{amount}} for {{defendant_name}} is now {{days_overdue}} days overdue. Please contact us immediately at (239) 332-2245 to avoid further action.'
    }
};

global.set('last_run_installPaymentRecon', ts);
node.status({fill:'green',shape:'dot',text:'Installing payment recon...'});
return msg;

/* Execute payment reconciliation NOW via GAS */
if (global.get('SYSTEM_SHUTDOWN')) {
    node.status({fill:'red',shape:'ring',text:'SHUTDOWN'});
    return null;
}

const gasUrl = global.get('GAS_URL_OPS') || global.get('GAS_URL');
if (!gasUrl) {
    node.error('No GAS URL configured');
    return null;
}

const ts = new Date().toISOString();
msg.payload = {
    action: 'runPaymentRecon',
    requestedAt: ts,
    source: 'node-red-dashboard',
    params: {
        dryRun: false,
        sendReminders: true,
        sendOverdueNotices: true,
        reconcileSwipeSimple: true,
        logToSlack: true,
        channels: ['sms', 'whatsapp']
    }
};

global.set('last_run_paymentRecon', ts);
node.status({fill:'green',shape:'dot',text:'Running payment recon...'});
return msg;

if (msg.payload && msg.payload.success) {
    msg.payload = msg.payload.events;
    return msg;
}
return null;

msg.payload = {
    'action': 'generateCourtDocument',
    'docType': msg.payload.docType.toLowerCase(),
    'caseData': {
        'defendantName': msg.payload.defendantName,
        'county': msg.payload.county,
        'courtName': 'CIRCUIT',
        'caseNumber': msg.payload.caseNumber,
        'bondAmount': msg.payload.bondAmount,
        'estreatureDate': msg.payload.estreatureDate
    }
};
msg.headers = {
    'x-api-key': global.get('gas_api_key') || ''
};
return msg;

let watchList = global.get('walkout_watch_list') || {};
watchList[msg.payload.bookingNum] = {
    phone: msg.payload.phone,
    status: 'WATCHING',
    added: new Date().toISOString()
};
global.set('walkout_watch_list', watchList);
msg.payload = `Now watching ${msg.payload.bookingNum} for release.`;
return msg;

let watchList = global.get('walkout_watch_list') || {};
let msgs = [];
for (let bookingNum in watchList) {
    if (watchList[bookingNum].status === 'WATCHING') {
        // In a real prod setup, this triggers the HTTP node to our Lee County Scraper Endpoint.
        // If scraper returns {"status": "RELEASED"}, we route to Twilio SMS and flip status to 'RELEASED_NOTIFIED'.
        msgs.push({ 
            payload: { bookingNum: bookingNum, phone: watchList[bookingNum].phone, action: 'check_status' } 
        });
    }
}
return [msgs];

let probList = global.get('probation_list') || {};
probList[msg.payload.defName] = {
    phone: msg.payload.phone,
    frequency: msg.payload.freq,
    last_checkin: null
};
global.set('probation_list', probList);
msg.payload = `Enrolled ${msg.payload.defName} for ${msg.payload.freq} check-ins.`;
return msg;

let probList = global.get('probation_list') || {};
let msgs = [];
for (let def in probList) {
    let text = `Shamrock Bail Bonds Auto Check-in: Hello ${def}, please reply with 'HERE' to legally verify your location and check-in for the ${probList[def].frequency} requirement.`;

    // In prod, this routes to the Twilio SMS outbound node
    msgs.push({ 
        payload: { to: probList[def].phone, text: text, _shamrock_ai_route: 'checkin_dispatch' } 
    });
}
return [msgs];

// Filter High Value & Returning — aligned with Master 34 schema
// Feeds Top Unposted Bonds (Shamrock's Leads) and Bounty Board
try {
    const rawData = typeof msg.payload === 'string' ? JSON.parse(msg.payload) : msg.payload;
    const records = Array.isArray(rawData) ? rawData :
                    (rawData && Array.isArray(rawData.data)) ? rawData.data :
                    (rawData && Array.isArray(rawData.arrests)) ? rawData.arrests :
                    (rawData && Array.isArray(rawData.records)) ? rawData.records : [rawData];

    // Historical client lookup from global CSV cache
    const historicalText = global.get('historical_clients_csv') || '';
    const isHistorical = (fullName) => {
        if (!historicalText || !fullName) return false;
        const normIncoming = fullName.toLowerCase().replace(/[^a-z]/g, '');
        if (normIncoming.length < 3) return false;
        const rows = historicalText.split('\n');
        for (let i = 1; i < rows.length; i++) {
            const cols = rows[i].split(',');
            if (cols.length >= 2) {
                const fName = (cols[0] || '').replace(/[^a-zA-Z]/g, '').toLowerCase();
                const lName = (cols[1] || '').replace(/[^a-zA-Z]/g, '').toLowerCase();
                if (fName && lName && normIncoming.includes(fName) && normIncoming.includes(lName)) {
                    return true;
                }
            }
        }
        return false;
    };

    let leads = [];
    for (const record of records) {
        // Master 34 schema: Bond_Amount (numeric), Status
        const statusText = (record.Status || record.status || record.bond_status || '').toLowerCase();
        const isUnposted = !statusText.includes('posted') || statusText.includes('unposted') || statusText === '';

        if (!isUnposted) continue;

        // Support all field name variants
        const bondVal = parseFloat(
            String(record.Bond_Amount || record.BondAmount || record.bondAmount ||
                   record.bond || record.total_bond_amount || '0')
            .replace(/[^0-9.]/g, '')
        ) || 0;

        const fullName = record.Full_Name || record.full_name || record.name || record.DefendantName || 'Unknown';
        const returning = isHistorical(fullName);

        if (bondVal > 2500 || returning) {
            leads.push({
                Full_Name:    fullName,
                Bond_Amount:  bondVal,
                County:       record.County || record.county || 'Unknown',
                Charges:      record.Charges || record.charges || 'Not Listed',
                Booking_Date: record.Booking_Date || record.booking_date || '',
                Status:       record.Status || record.status || 'Unposted',
                Lead_Score:   record.Lead_Score || record.leadScore || 0,
                isReturning:  returning,
                // Keep original fields too for compatibility
                bond:         bondVal,
                name:         fullName,
                county:       record.County || record.county || 'Unknown',
                charges:      record.Charges || record.charges || 'Not Listed'
            });
        }
    }

    // Sort: returning clients first, then by bond amount
    leads.sort((a, b) => {
        if (a.isReturning !== b.isReturning) return a.isReturning ? -1 : 1;
        return b.Bond_Amount - a.Bond_Amount;
    });

    const top20 = leads.slice(0, 20);

    // Persist to global context for periodic refresh
    global.set('shamrock_leads', top20);
    global.set('shamrock_leads_ts', new Date().toISOString());

    msg.payload = top20;
    node.status({fill: 'green', shape: 'dot', text: top20.length + ' leads (' + leads.length + ' total)'});
    return msg;
} catch (e) {
    node.error('Filter High Value error: ' + e.message);
    node.status({fill: 'red', shape: 'dot', text: 'Error: ' + e.message});
    return null;
}

// Cache data to global context with TTL, validation, and size cap
const key = msg.topic || 'historical_clients_csv';
const data = msg.payload;
const ttlMinutes = msg.ttl || 60;

// Validate data exists
if (!data) {
    node.warn('Cache to Global: No data to cache');
    node.status({ fill: 'yellow', shape: 'ring', text: 'No data received' });
    return null;
}

// Size check (cap at 5MB)
const dataSize = JSON.stringify(data).length;
if (dataSize > 5 * 1024 * 1024) {
    node.warn(`Cache to Global: Data too large (${(dataSize / 1024 / 1024).toFixed(1)}MB)`);
    node.status({ fill: 'red', shape: 'ring', text: 'Data exceeds 5MB limit' });
    return null;
}

// Store with metadata
global.set(key, data);
global.set(`${key}_meta`, {
    cachedAt: new Date().toISOString(),
    expiresAt: new Date(Date.now() + ttlMinutes * 60 * 1000).toISOString(),
    sizeBytes: dataSize,
    source: msg._msgid || 'unknown'
});

node.status({
    fill: 'green',
    shape: 'dot',
    text: `Cached ${key} (${(dataSize / 1024).toFixed(1)}KB) TTL: ${ttlMinutes}m`
});

// Pass through instead of dropping
msg.cached = { key, sizeBytes: dataSize, ttlMinutes };
return msg;

const err = msg.error || {};
const source = err.source ? (err.source.name || err.source.type || err.source.id) : "Unknown Node";
const text = `🚨 *Node-RED CRITICAL ERROR* 🚨\n\n*Source Node:* ${source}\n*Error Message:* ${err.message || "Unknown Error"}\n\n` + "```" + JSON.stringify(msg, null, 2).substring(0, 500) + "```";

msg.headers = {
    "Authorization": "Bearer " + ((global.get("env").SLACK_BOT_TOKEN || global.get("SLACK_TOKEN") || "") || ""),
    "Content-Type": "application/json; charset=utf-8"
};

msg.payload = {
    "channel": "#alerts",
    "text": text
};

return msg;

// IRB Relative Search — GAS-backed with simulated fallback
const firstName = (msg.payload.firstName || '').trim();
const lastName = (msg.payload.lastName || '').trim();
const dob = msg.payload.dateOfBirth || msg.payload.dob || '';
const bailAgentName = msg.payload.bailAgentName || 'Shamrock Agent';

if (!firstName || !lastName) {
    node.warn('First and Last name required for IRB search');
    return null;
}

// Channel selections from form checkboxes
const channels = {
    sms:       msg.payload.smsEnabled !== false,
    whatsapp:  msg.payload.whatsappEnabled === true,
    telegram:  msg.payload.telegramEnabled === true,
    email:     msg.payload.emailEnabled === true,
    voice:     msg.payload.voiceEnabled === true
};

// Store search context for outreach pipeline
const searchCtx = {
    defendant: firstName + ' ' + lastName,
    firstName: firstName,
    lastName: lastName,
    dob: dob,
    bailAgentName: bailAgentName,
    channels: channels,
    searchedAt: new Date().toISOString()
};
global.set('last_irb_search', searchCtx);
global.set('irb_search_query', firstName + ' ' + lastName);

// Build GAS IRB request
