}

const phone = (p.client_phone || '').replace(/\D/g, '');
if (phone.length < 10) {
    node.error('Invalid phone number');
    node.status({fill:'red',shape:'ring',text:'Invalid phone'});
    return null;
}

const ts = new Date().toISOString();
msg.payload = {
    action: 'sendCourtReminderOverride',
