    source: 'node-red-dashboard',
    params: {
        phone: '+1' + phone,
        defendantName: p.defendant_name || 'Defendant',
        caseNumber: p.case_number || '',
        courtDate: p.court_date,
        courtLocation: p.court_location || '',
        channels: ['sms'],
        urgency: 'immediate'
    }
};

node.status({fill:'green',shape:'dot',text:'Override → +1' + phone.slice(-4)});
return msg;

