const combined = [...leads, ...bountyData];
const seen = new Set();
const deduped = combined.filter(l => {
    const key = (l.Full_Name || l.name || '') + (l.Bond_Amount || l.bond || 0);
    if (seen.has(key)) return false;
    seen.add(key);
    return true;
});

deduped.sort((a, b) => {
    const ba = parseFloat(String(a.Bond_Amount || a.BondAmount || a.bond || 0).replace(/[^0-9.]/g,'')) || 0;
    const bb = parseFloat(String(b.Bond_Amount || b.BondAmount || b.bond || 0).replace(/[^0-9.]/g,'')) || 0;
    return bb - ba;
});

