    node.warn('MONGODB_URI not configured — falling back to GAS fetch');
    // Fall through to GAS fetch via output 2
    msg.payload = {
        action: 'fetchLatestArrests',
        apiKey: global.get('gas_api_key') || '',
        counties: ['lee', 'collier', 'charlotte'],
        hoursBack: 6,
        minBondAmount: 0,
        source: 'node-red-dashboard'
    };
    return [null, null, msg];
}

// Build MongoDB query payload for the HTTP request node
// We use the MongoDB Atlas Data API (REST)
const atlasApiUrl = env.get('MONGODB_ATLAS_DATA_API_URL') || '';
const atlasApiKey = env.get('MONGODB_ATLAS_API_KEY') || '';

if (atlasApiUrl && atlasApiKey) {
    // Use Atlas Data API (serverless REST endpoint)
    msg.url = atlasApiUrl + '/action/find';
    msg.method = 'POST';
    msg.headers = {
        'Content-Type': 'application/json',
        'api-key': atlasApiKey
    };
    msg.payload = {
        dataSource: 'shamrock',
        database: 'shamrock_arrests',
        collection: 'arrests',
        filter: {
            Booking_Date: {
                $gte: new Date(Date.now() - 6 * 60 * 60 * 1000).toISOString().split('T')[0]
            }
        },
        sort: { _created_at: -1 },
        limit: 50
    };
    node.status({fill:'blue', shape:'dot', text:'Querying Atlas...'});
    return [msg, null, null];
} else {
    // Fall back to GAS fetch
    node.warn('Atlas Data API not configured — using GAS fetch');
    msg.payload = {
        action: 'fetchLatestArrests',
        apiKey: global.get('gas_api_key') || '',
        counties: ['lee', 'collier', 'charlotte'],
        hoursBack: 6,
        minBondAmount: 0,
        source: 'node-red-dashboard'
    };
    return [null, null, msg];
}

// Process MongoDB Atlas Data API response → normalize to Master 34
try {
    const data = msg.payload;
    // Atlas Data API returns { documents: [...] }
    const docs = (data && Array.isArray(data.documents)) ? data.documents :
                 Array.isArray(data) ? data : [];

    if (docs.length === 0) {
        node.status({fill:'grey', shape:'ring', text:'No records from Atlas'});
        return null;
    }

    // Normalize to Master 34 schema
    const normalized = docs.map(d => ({
        Full_Name:      d.Full_Name || d.full_name || d.name || 'Unknown',
        Bond_Amount:    parseFloat(String(d.Bond_Amount || d.bond_amount || '0').replace(/[^0-9.]/g,'')) || 0,
        County:         d.County || d.county || 'Unknown',
        Charges:        d.Charges || d.charges || 'Pending',
        Booking_Date:   d.Booking_Date || d.booking_date || '',
        Booking_Number: d.Booking_Number || d.booking_number || '',
        Status:         d.Status || d.status || 'Unposted',
        Mugshot_URL:    d.Mugshot_URL || d.mugshot_url || '',
        _isNew:         false
    }));

    normalized.sort((a, b) => b.Bond_Amount - a.Bond_Amount);

    // Update global context
    global.set('latest_bookings', normalized);
    global.set('latest_bookings_ts', new Date().toISOString());

    msg.payload = normalized;
    node.status({fill:'green', shape:'dot', text: normalized.length + ' from Atlas'});
    return msg;
} catch (e) {
    node.error('MongoDB process error: ' + e.message);
    return null;
}

