// Build outreach status events from Twilio/ElevenLabs responses
try {
    const result = msg.payload;
    let events = global.get('outreach_events') || [];

    // Parse Twilio SMS response
    if (result && (result.sid || result.status)) {
        const evt = {
            channel: msg.channel || 'sms',
            target_name: msg.targetName || msg.target_name || 'Contact',
            phone: msg.targetPhone || msg.target_phone || result.to || '—',
            status: result.status || 'sent',
            timestamp: new Date().toLocaleTimeString('en-US', {hour:'2-digit', minute:'2-digit'}),
            sid: result.sid || ''
        };
        events.unshift(evt);
        if (events.length > 20) events = events.slice(0, 20);
        global.set('outreach_events', events);
    }

    msg.payload = events;
    node.status({fill:'green', shape:'dot', text: events.length + ' events'});
    return msg;
} catch (e) {
    node.error('Outreach status error: ' + e.message);
    return null;
}

// Save High-Risk Target to global watchlist
const input = (msg.payload || '').toString().trim();
if (!input) {
    node.warn('No target name/charge provided');
    return null;
}

// Parse: "John Doe / Drug Trafficking" or just "John Doe"
const parts = input.split('/').map(s => s.trim());
const targetName = parts[0] || input;
const targetCharge = parts[1] || 'Unspecified';

const watchlist = global.get('high_risk_watchlist') || [];

// Deduplicate
const exists = watchlist.some(t => t.name.toLowerCase() === targetName.toLowerCase());
if (exists) {
    node.status({fill:'yellow', shape:'ring', text:'Already on watchlist'});
    msg.payload = {status: 'duplicate', message: targetName + ' already on watchlist'};
    return msg;
}

watchlist.unshift({
    name: targetName,
    charge: targetCharge,
    added: new Date().toISOString(),
    addedBy: 'dashboard'
});

// Keep max 50 targets
if (watchlist.length > 50) watchlist.pop();
global.set('high_risk_watchlist', watchlist);

node.status({fill:'green', shape:'dot', text:'Added: ' + targetName});
msg.payload = {
    status: 'added',
    message: '✅ ' + targetName + ' added to watchlist',
    watchlist: watchlist
};
return msg;

// Process GAS scraper trigger response
// GAS returns status + any immediately available records
try {
    const resp = msg.payload;
    const status = resp.status || resp.result || 'unknown';
    const records = Array.isArray(resp.records) ? resp.records :
                    Array.isArray(resp.arrests) ? resp.arrests :
                    Array.isArray(resp.data) ? resp.data : [];

    node.status({fill: status === 'ok' || status === 'success' ? 'green' : 'yellow',
                 shape: 'dot',
                 text: status + (records.length ? ' (' + records.length + ' records)' : '')});

    if (records.length > 0) {
        // Normalize and push to dashboard
        const normalized = records.map(r => ({
            Full_Name:    r.Full_Name || r.full_name || r.name || 'Unknown',
            Bond_Amount:  parseFloat(String(r.Bond_Amount || r.BondAmount || r.bond || '0').replace(/[^0-9.]/g,'')) || 0,
            County:       r.County || r.county || 'Unknown',
            Charges:      r.Charges || r.charges || 'Pending',
            Booking_Date: r.Booking_Date || r.booking_date || '',
            Status:       r.Status || r.status || 'Unposted',
            _isNew:       true
        }));
        normalized.sort((a,b) => b.Bond_Amount - a.Bond_Amount);

        // Merge with existing bookings
        const existing = global.get('latest_bookings') || [];
        const merged = [...normalized, ...existing.filter(e =>
            !normalized.some(n => n.Full_Name === e.Full_Name && n.Booking_Date === e.Booking_Date)
        )].slice(0, 50);

        global.set('latest_bookings', merged);
        global.set('latest_bookings_ts', new Date().toISOString());
        msg.payload = merged;
        return msg;
    }

    msg.payload = global.get('latest_bookings') || [];
    return msg;
} catch (e) {
    node.error('Process scraper response error: ' + e.message);
    return null;
}

