const ts = new Date().toISOString();

// Drip campaign configuration
// GAS will use these tiers to select the right message template
msg.url = gasUrl;
msg.method = 'POST';
msg.headers = { 'Content-Type': 'application/json' };
msg.payload = {
    action: 'runDripCampaign',
    requestedAt: ts,
    source: 'node-red',
    maxPerRun: 30,
    dripSteps: [
        { step: 1, label: 'Immediate',       minHours: 0,   maxHours: 1,   template: 'drip_immediate' },
        { step: 2, label: '24h Value Prop',   minHours: 23,  maxHours: 25,  template: 'drip_value_prop' },
        { step: 3, label: '72h Check-In',     minHours: 71,  maxHours: 73,  template: 'drip_check_in' },
        { step: 4, label: '7-Day Final',      minHours: 167, maxHours: 169, template: 'drip_final' }
    ],
    respectPreferences: true,
    channels: ['sms', 'whatsapp', 'telegram']
};

global.set('last_run_dripCampaign', ts);
node.status({fill:'blue',shape:'dot',text:'Running drip scan @ ' + new Date().toLocaleTimeString()});
return msg;

// Parse GAS drip campaign response
var data = msg.payload;
try {
    if (typeof data === 'string') data = JSON.parse(data);
} catch(e) {
    node.warn('Drip campaign: non-JSON response: ' + (data || '').substring(0, 200));
    msg.payload = { status: 'error', error: 'Non-JSON response' };
    return msg;
}

if (!data || data.status === 'error') {
    node.status({fill:'red',shape:'dot',text:'Error: ' + (data?.error || 'unknown')});
    return msg;
}

// Store drip results for dashboard
const results = data.data || data.results || data;
global.set('drip_results', results);
global.set('drip_results_updated', new Date().toISOString());

// Track cumulative stats
const stats = global.get('drip_stats') || { totalSent: 0, byStep: {1:0,2:0,3:0,4:0}, conversions: 0 };
if (results.sent) {
    stats.totalSent += results.sent;
    if (results.byStep) {
        for (const [step, count] of Object.entries(results.byStep)) {
            stats.byStep[step] = (stats.byStep[step] || 0) + count;
        }
    }
    if (results.conversions) stats.conversions += results.conversions;
}
global.set('drip_stats', stats);

msg.dripResult = results;
msg.dripStats = stats;
node.status({fill:'green',shape:'dot',text:'Sent: ' + (results.sent || 0) + ' | Conv: ' + (results.conversions || 0)});
return msg;

// Format drip campaign results for Slack
msg.headers = {
    "Authorization": "Bearer " + (global.get("env").SLACK_BOT_TOKEN || global.get("SLACK_TOKEN") || ""),
    "Content-Type": "application/json; charset=utf-8"
};

const r = msg.dripResult || {};
const s = msg.dripStats || {};
const sent = r.sent || 0;
const skipped = r.skipped || 0;
const total = sent + skipped;

// Only post to Slack if something happened
if (sent === 0 && skipped === 0) {
    node.status({fill:'grey',shape:'ring',text:'No leads in window'});
    return null; // Don't post empty reports
}

const stepBreakdown = r.byStep
    ? Object.entries(r.byStep).map(([step, count]) => {
        const labels = { '1': '⚡ Immediate', '2': '💎 Value Prop', '3': '🤔 Check-In', '4': '👋 Final' };
        return `  ${labels[step] || 'Step ' + step}: ${count}`;
      }).join('\n')
    : '  (no breakdown available)';

msg.payload = {
    "channel": "#leads",
    "text": `📧 *Drip Campaign Report*\n\n📊 Scanned: ${total}\n📤 Sent: ${sent}\n⏭️ Skipped: ${skipped}\n\n*By Step:*\n${stepBreakdown}\n\n📈 _Cumulative: ${s.totalSent || 0} sent | ${s.conversions || 0} conversions_`
};
return msg;

/* T-015: MongoDB direct query for high-value unposted bonds */
if (global.get('SYSTEM_SHUTDOWN')) {
    node.status({fill:'red',shape:'ring',text:'SHUTDOWN'});
    return null;
}

const mongoUri = global.get('env').MONGODB_URI;
if (!mongoUri) {
    node.status({fill:'yellow',shape:'ring',text:'No MONGODB_URI — falling back to GAS'});
    return null; // GAS chain handles this
}

// Query: unposted bonds > $2,500, sorted by bond_amount desc
msg.collection = 'arrests';
msg.operation = 'find';
msg.payload = {
    bond_amount: { $gt: 2500 },
    status: { $nin: ['posted', 'bonded_out', 'released'] }
};
msg.projection = {
    defendant_name: 1,
    booking_number: 1,
    bond_amount: 1,
    charges: 1,
    county: 1,
    booking_date: 1,
    facility: 1,
    _id: 0
};
msg.sort = { bond_amount: -1 };
msg.limit = 50;

node.status({fill:'blue',shape:'dot',text:'Querying MongoDB...'});
return msg;

// Format MongoDB bounty results for dashboard
const results = msg.payload || [];
const now = new Date();

// Enrich with scoring
const scored = results.map(r => {
    let score = 0;
    const amt = r.bond_amount || 0;

    // Bond amount scoring
    if (amt >= 50000) score += 40;
    else if (amt >= 25000) score += 30;
    else if (amt >= 10000) score += 20;
    else if (amt >= 5000) score += 10;
    else score += 5;

    // Recency scoring
    const bookDate = new Date(r.booking_date);
    const hoursOld = (now - bookDate) / (1000 * 60 * 60);
    if (hoursOld < 6) score += 30;       // Very fresh
    else if (hoursOld < 24) score += 20;  // Fresh
    else if (hoursOld < 72) score += 10;  // Recent

    // Charge severity (basic heuristic)
    const charges = (r.charges || '').toLowerCase();
    if (charges.includes('dui') || charges.includes('dwi')) score += 15;
    if (charges.includes('domestic') || charges.includes('battery')) score += 10;
    if (charges.includes('felony')) score += 20;

    return { ...r, score, hoursOld: Math.round(hoursOld) };
}).sort((a, b) => b.score - a.score);

// Store for dashboard
global.set('mongo_bounty_board', scored);
global.set('mongo_bounty_updated', now.toISOString());
global.set('mongo_bounty_count', scored.length);

// Summary stats
const totalValue = scored.reduce((sum, r) => sum + (r.bond_amount || 0), 0);
const counties = [...new Set(scored.map(r => r.county).filter(Boolean))];

msg.bountyData = {
    leads: scored,
    totalCount: scored.length,
    totalValue: totalValue,
    counties: counties,
    hotLeads: scored.filter(r => r.score >= 50).length,
    warmLeads: scored.filter(r => r.score >= 25 && r.score < 50).length
};

node.status({fill:'green',shape:'dot',text: scored.length + ' leads | $' + totalValue.toLocaleString()});
return msg;

// Store aggregate stats for dashboard widgets
const d = msg.bountyData || {};
const stats = global.get('mongo_dashboard_stats') || { history: [] };

stats.lastUpdate = new Date().toISOString();
stats.activeLeads = d.totalCount || 0;
stats.totalBondValue = d.totalValue || 0;
stats.hotLeads = d.hotLeads || 0;
stats.warmLeads = d.warmLeads || 0;
stats.counties = d.counties || [];

// Keep last 24 data points for trend chart
stats.history.push({
    ts: Date.now(),
    count: d.totalCount || 0,
    value: d.totalValue || 0
});
if (stats.history.length > 24) stats.history.shift();

global.set('mongo_dashboard_stats', stats);
node.status({fill:'green',shape:'dot',text:'Stats stored'});
return msg;

/* T-015: MongoDB aggregation for arrest analytics */
if (global.get('SYSTEM_SHUTDOWN')) return null;

const mongoUri = global.get('env').MONGODB_URI;
if (!mongoUri) {
    node.status({fill:'yellow',shape:'ring',text:'No MONGODB_URI'});
    return null;
}

// Aggregation pipeline: arrests by county in last 30 days
const thirtyDaysAgo = new Date(Date.now() - 30 * 24 * 60 * 60 * 1000);

msg.collection = 'arrests';
msg.operation = 'aggregate';
msg.payload = [
    { $match: { booking_date: { $gte: thirtyDaysAgo.toISOString() } } },
    { $group: {
        _id: { county: '$county', day: { $substr: ['$booking_date', 0, 10] } },
        count: { $sum: 1 },
        totalBond: { $sum: '$bond_amount' },
        avgBond: { $avg: '$bond_amount' }
    }},
    { $group: {
        _id: '$_id.county',
        dailyData: { $push: { day: '$_id.day', count: '$count', totalBond: '$totalBond' } },
        totalArrests: { $sum: '$count' },
        totalBondValue: { $sum: '$totalBond' },
        avgBondPerArrest: { $avg: '$avgBond' }
    }},
    { $sort: { totalArrests: -1 } }
];

node.status({fill:'blue',shape:'dot',text:'Running analytics pipeline...'});
return msg;

// Format MongoDB analytics for dashboard
const results = msg.payload || [];

const analytics = {
    lastUpdate: new Date().toISOString(),
    counties: {},
    totals: { arrests: 0, bondValue: 0 }
};

results.forEach(county => {
    analytics.counties[county._id || 'Unknown'] = {
        totalArrests: county.totalArrests || 0,
        totalBondValue: Math.round(county.totalBondValue || 0),
        avgBondPerArrest: Math.round(county.avgBondPerArrest || 0),
        dailyTrend: (county.dailyData || []).sort((a, b) => a.day.localeCompare(b.day))
    };
    analytics.totals.arrests += county.totalArrests || 0;
    analytics.totals.bondValue += county.totalBondValue || 0;
});

global.set('mongo_arrest_analytics', analytics);

node.status({fill:'green',shape:'dot',text:
    results.length + ' counties | ' + 
    analytics.totals.arrests + ' arrests | $' + 
    analytics.totals.bondValue.toLocaleString()
});
return msg;

// T-021: Communication Preference Enforcement
// Checks if we're allowed to send to this client via the specified channel
// msg.channel = 'sms' | 'whatsapp' | 'telegram' | 'email' | 'voice'
// msg.phone = client phone number (used as lookup key)

const phone = msg.phone || msg.payload?.phone || '';
const channel = msg.channel || 'sms'; // default to SMS

if (!phone) {
    // No phone number — can't check prefs, allow through
    node.status({fill:'yellow',shape:'ring',text:'No phone — skipping pref check'});
    return [msg, null];
}

// Normalize phone for lookup
const normalPhone = phone.replace(/\D/g, '').slice(-10);

// Check cached preferences (populated by GAS via scheduled sync)
const prefs = global.get('comm_preferences') || {};
const clientPref = prefs[normalPhone];

if (!clientPref) {
    // No prefs on file — default to ALLOW (opt-out model)
    node.status({fill:'green',shape:'dot',text:'No prefs — allowed'});
    msg.prefStatus = 'no_prefs_default_allow';
    return [msg, null];
}

// Check if this channel is allowed
const channelMap = {
    sms: clientPref.sms !== false,         // Default: true
    whatsapp: clientPref.whatsapp !== false,
    telegram: clientPref.telegram !== false,
    email: clientPref.email !== false,
    voice: clientPref.voice !== false
};

const allowed = channelMap[channel] !== false;

if (allowed) {
    node.status({fill:'green',shape:'dot',text:channel + ' — ALLOWED'});
    msg.prefStatus = 'allowed';
    return [msg, null];
} else {
    node.status({fill:'red',shape:'ring',text:channel + ' — BLOCKED by pref'});
    msg.prefStatus = 'blocked';
    msg.blockedReason = 'Client opted out of ' + channel;
    return [null, msg];
}

// T-024: Build portal deep links for SMS/WhatsApp messages
// Generates links to Telegram Mini-App or Wix Portal

const TELEGRAM_BASE = 'https://shamrock-telegram.netlify.app';
const WIX_BASE = 'https://www.shamrockbailbonds.biz';
const BOT_DEEPLINK = 'https://t.me/ShamrockBail_bot?start=';

const linkType = msg.linkType || msg.payload?.linkType || 'status';
const caseId = msg.caseId || msg.payload?.caseId || '';

const ROUTES = {
    // Telegram Mini-App routes
    court:   { tg: TELEGRAM_BASE + '/status',   wix: WIX_BASE + '/court-dates',  label: 'View Court Date' },
    payment: { tg: TELEGRAM_BASE + '/payments',  wix: WIX_BASE + '/payments',     label: 'Make Payment' },
    checkin: { tg: TELEGRAM_BASE + '/checkin',   wix: WIX_BASE + '/check-in',     label: 'Check In' },
    status:  { tg: TELEGRAM_BASE + '/status',    wix: WIX_BASE + '/case-status',  label: 'Case Status' },
    intake:  { tg: TELEGRAM_BASE + '/intake',    wix: WIX_BASE + '/intake',       label: 'Start Intake' },
    docs:    { tg: TELEGRAM_BASE + '/documents', wix: WIX_BASE + '/documents',    label: 'View Documents' }
};

const route = ROUTES[linkType] || ROUTES.status;

// Build links with case ID parameter if available
const params = caseId ? '?caseId=' + encodeURIComponent(caseId) : '';
msg.deepLink = route.tg + params;
msg.wixLink = route.wix + params;
msg.botLink = BOT_DEEPLINK + linkType + (caseId ? '_' + caseId : '');
msg.linkLabel = route.label;

// Formatted SMS snippet
msg.smsSnippet = route.label + ': ' + msg.deepLink;

node.status({fill:'green',shape:'dot',text:linkType + ' → ' + msg.deepLink.substring(0, 40) + '...'});
return msg;

// Fetch all client communication preferences from GAS
const gasUrl = global.get('env').GAS_WEBHOOK_URL;
if (!gasUrl) return null;

msg.url = gasUrl;
msg.method = 'POST';
msg.headers = { 'Content-Type': 'application/json' };
msg.payload = {
    action: 'getCommPreferences',
    source: 'node-red'
};

node.status({fill:'blue',shape:'dot',text:'Syncing prefs...'});
return msg;

// Store preference map in global context
// Expected: { "2395551234": { sms: true, whatsapp: false, ... }, ... }
var data = msg.payload;
try {
    if (typeof data === 'string') data = JSON.parse(data);
} catch(e) {
    node.warn('Pref sync: non-JSON response');
    return null;
}

const prefs = data.data || data.preferences || data;
if (prefs && typeof prefs === 'object') {
    global.set('comm_preferences', prefs);
    global.set('comm_preferences_updated', new Date().toISOString());
    const count = Object.keys(prefs).length;
    node.status({fill:'green',shape:'dot',text:count + ' prefs cached @ ' + new Date().toLocaleTimeString()});
} else {
    node.status({fill:'yellow',shape:'ring',text:'No prefs returned'});
}
return msg;
